-- ============================================================================
-- Message Mesh - H2 Repository Test Queries
-- ----------------------------------------------------------------------------
-- Run these in the H2 console (http://localhost:8080/h2-console).
-- JDBC URL: jdbc:h2:file:./data/chatdb;AUTO_SERVER=TRUE   user: sa   pass: (blank)
--
-- Tables are auto-generated by Hibernate (ddl-auto: update) using Spring Boot's
-- default naming strategy (camelCase -> snake_case columns):
--   users             (id, username, password_hash, display_name, role, active, token_version, created_at)
--   conversations     (id, type, title, created_by, deleted, created_at)
--   memberships       (id, user_id, conversation_id, role, last_read_seq, muted, archived, joined_at)
--   chat_messages     (id, conversation_id, sender_username, seq, body, status, edited_at, deleted, parent_id, created_at)
--   message_reactions (id, message_id, username, emoji, created_at)
--   audit_events      (id, actor_username, action, target_type, target_id, details, created_at)
--
-- Each section below mirrors a repository method. Replace the sample UUIDs
-- with your own values as needed.
-- ============================================================================


-- ============================================================================
-- 0. SAMPLE SEED DATA (optional - run once to have rows to query against)
-- ============================================================================
-- Users (role: USER | ADMIN, active: TRUE | FALSE, token_version bumped to revoke sessions)
INSERT INTO users (id, username, password_hash, display_name, role, active, token_version, created_at) VALUES
  ('11111111-1111-1111-1111-111111111111', 'alice', '$2a$10$hashAlice', 'Alice', 'ADMIN', TRUE, 0, CURRENT_TIMESTAMP),
  ('22222222-2222-2222-2222-222222222222', 'bob',   '$2a$10$hashBob',   'Bob',   'USER',  TRUE, 0, CURRENT_TIMESTAMP),
  ('33333333-3333-3333-3333-333333333333', 'carol', '$2a$10$hashCarol', 'Carol', 'USER',  TRUE, 0, CURRENT_TIMESTAMP);

-- Promote an existing user to administrator (used by the admin flow):
--   UPDATE users SET role = 'ADMIN' WHERE username = 'alice';
-- Deactivate a user (blocks login, rejects existing sessions):
--   UPDATE users SET active = FALSE WHERE username = 'bob';
-- Force logout everywhere (revoke sessions) by advancing the token version:
--   UPDATE users SET token_version = token_version + 1 WHERE username = 'bob';

-- Conversations (one DIRECT alice<->bob, one GROUP). created_by = owner; deleted = soft-delete flag
INSERT INTO conversations (id, type, title, created_by, deleted, created_at) VALUES
  ('aaaaaaaa-0000-0000-0000-000000000001', 'DIRECT', NULL,        'alice', FALSE, CURRENT_TIMESTAMP),
  ('aaaaaaaa-0000-0000-0000-000000000002', 'GROUP',  'Team Chat', 'alice', FALSE, CURRENT_TIMESTAMP);

-- Memberships (muted/archived are per-user prefs; joined_at defaults to now)
INSERT INTO memberships (id, user_id, conversation_id, role, last_read_seq, muted, archived, joined_at) VALUES
  ('bbbbbbbb-0000-0000-0000-000000000001', '11111111-1111-1111-1111-111111111111', 'aaaaaaaa-0000-0000-0000-000000000001', 'MEMBER', 0, FALSE, FALSE, CURRENT_TIMESTAMP),
  ('bbbbbbbb-0000-0000-0000-000000000002', '22222222-2222-2222-2222-222222222222', 'aaaaaaaa-0000-0000-0000-000000000001', 'MEMBER', 0, FALSE, FALSE, CURRENT_TIMESTAMP),
  ('bbbbbbbb-0000-0000-0000-000000000003', '11111111-1111-1111-1111-111111111111', 'aaaaaaaa-0000-0000-0000-000000000002', 'ADMIN',  0, FALSE, FALSE, CURRENT_TIMESTAMP),
  ('bbbbbbbb-0000-0000-0000-000000000004', '22222222-2222-2222-2222-222222222222', 'aaaaaaaa-0000-0000-0000-000000000002', 'MEMBER', 0, FALSE, FALSE, CURRENT_TIMESTAMP),
  ('bbbbbbbb-0000-0000-0000-000000000005', '33333333-3333-3333-3333-333333333333', 'aaaaaaaa-0000-0000-0000-000000000002', 'MEMBER', 0, FALSE, FALSE, CURRENT_TIMESTAMP);

-- Messages (edited_at set on edit; deleted = soft-delete tombstone; parent_id = threaded reply)
INSERT INTO chat_messages (id, conversation_id, sender_username, seq, body, status, edited_at, deleted, parent_id, created_at) VALUES
  ('cccccccc-0000-0000-0000-000000000001', 'aaaaaaaa-0000-0000-0000-000000000001', 'alice', 1, 'Hi Bob',       'READ',      NULL, FALSE, NULL,                                     CURRENT_TIMESTAMP),
  ('cccccccc-0000-0000-0000-000000000002', 'aaaaaaaa-0000-0000-0000-000000000001', 'bob',   2, 'Hey Alice',    'DELIVERED', NULL, FALSE, 'cccccccc-0000-0000-0000-000000000001',   CURRENT_TIMESTAMP),
  ('cccccccc-0000-0000-0000-000000000003', 'aaaaaaaa-0000-0000-0000-000000000001', 'alice', 3, 'How are you?', 'SENT',      NULL, FALSE, NULL,                                     CURRENT_TIMESTAMP),
  ('cccccccc-0000-0000-0000-000000000004', 'aaaaaaaa-0000-0000-0000-000000000002', 'alice', 1, 'Welcome all',  'SENT',      NULL, FALSE, NULL,                                     CURRENT_TIMESTAMP);

-- Reactions (unique per message_id + username + emoji; emoji from the fixed palette 👍 ❤️ 😂 😮 😢 🙏)
