-- ============================================================================
-- 1. UserRepository
-- ============================================================================

-- findByUsername(String username)
SELECT * FROM users
WHERE username = 'alice';

-- existsByUsername(String username)  -> returns count > 0
SELECT COUNT(*) > 0 AS exists_flag FROM users
WHERE username = 'alice';

-- findById(UUID id)  (JpaRepository)
SELECT * FROM users
WHERE id = '11111111-1111-1111-1111-111111111111';

-- findAll()  (JpaRepository)
SELECT * FROM users;

-- search(q, role, active, Pageable): admin user search; any filter left NULL is ignored.
-- Example: free-text 'a' + role ADMIN + active only, first 20 by username.
SELECT * FROM users
WHERE (LOWER(username) LIKE LOWER('%a%') OR LOWER(display_name) LIKE LOWER('%a%'))
  AND role = 'ADMIN'
  AND active = TRUE
ORDER BY username ASC
LIMIT 20 OFFSET 0;

-- countByActive(boolean): active vs inactive counts (dashboard stats)
SELECT COUNT(*) AS active_users   FROM users WHERE active = TRUE;
SELECT COUNT(*) AS inactive_users FROM users WHERE active = FALSE;

-- countByRole(UserRole): number of administrators
SELECT COUNT(*) AS admin_users FROM users WHERE role = 'ADMIN';

-- countByCreatedAtAfter(Instant): new users in the last 7 days
SELECT COUNT(*) AS new_users_7d FROM users
WHERE created_at > DATEADD('DAY', -7, CURRENT_TIMESTAMP);


-- ============================================================================
-- 2. ConversationRepository
-- ============================================================================

-- findAllForUser(UUID userId): non-deleted, non-archived conversations the user belongs to, newest first
SELECT c.* FROM conversations c
WHERE c.deleted = FALSE
  AND c.id IN (
    SELECT m.conversation_id FROM memberships m
    WHERE m.user_id = '11111111-1111-1111-1111-111111111111'
      AND m.archived = FALSE
)
ORDER BY c.created_at DESC;

-- findDirectBetween(UUID userA, UUID userB): DIRECT conversation shared by both
-- (also backs findExistingDirect, which just takes the first result)
SELECT c.* FROM conversations c
WHERE c.type = 'DIRECT'
  AND EXISTS (SELECT 1 FROM memberships m1
              WHERE m1.conversation_id = c.id
                AND m1.user_id = '11111111-1111-1111-1111-111111111111')
  AND EXISTS (SELECT 1 FROM memberships m2
              WHERE m2.conversation_id = c.id
                AND m2.user_id = '22222222-2222-2222-2222-222222222222')
ORDER BY c.created_at ASC;

-- findById(UUID id)  (JpaRepository)
SELECT * FROM conversations
WHERE id = 'aaaaaaaa-0000-0000-0000-000000000001';

-- search(q, type, deleted, Pageable): admin conversation search; any filter left NULL is ignored.
-- Example: title contains 'team', GROUP only, not deleted, newest first.
SELECT * FROM conversations
WHERE LOWER(title) LIKE LOWER('%team%')
  AND type = 'GROUP'
  AND deleted = FALSE
ORDER BY created_at DESC
LIMIT 20 OFFSET 0;

-- findByTitleContainingIgnoreCase(title, Pageable)
SELECT * FROM conversations
WHERE LOWER(title) LIKE LOWER('%chat%')
ORDER BY created_at DESC;

-- countByType(ConversationType): group vs direct counts (dashboard stats)
SELECT COUNT(*) AS group_conversations  FROM conversations WHERE type = 'GROUP';
SELECT COUNT(*) AS direct_conversations FROM conversations WHERE type = 'DIRECT';

-- countByDeleted(boolean): soft-deleted conversation count
SELECT COUNT(*) AS deleted_conversations FROM conversations WHERE deleted = TRUE;

-- Soft-delete / restore a conversation (admin moderation)
--   UPDATE conversations SET deleted = TRUE  WHERE id = 'aaaaaaaa-0000-0000-0000-000000000002';
--   UPDATE conversations SET deleted = FALSE WHERE id = 'aaaaaaaa-0000-0000-0000-000000000002';


-- ============================================================================
-- 3. MembershipRepository
-- ============================================================================

-- findByConversationId(UUID conversationId)
SELECT * FROM memberships
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000002';

-- findByUserId(UUID userId)
SELECT * FROM memberships
WHERE user_id = '11111111-1111-1111-1111-111111111111';

-- findByUserIdAndConversationId(UUID userId, UUID conversationId)
SELECT * FROM memberships
WHERE user_id = '11111111-1111-1111-1111-111111111111'
  AND conversation_id = 'aaaaaaaa-0000-0000-0000-000000000001';

-- existsByUserIdAndConversationId(UUID userId, UUID conversationId)
SELECT COUNT(*) > 0 AS exists_flag FROM memberships
WHERE user_id = '33333333-3333-3333-3333-333333333333'
  AND conversation_id = 'aaaaaaaa-0000-0000-0000-000000000002';

-- countByConversationId(UUID conversationId)
SELECT COUNT(*) AS member_count FROM memberships
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000002';

-- countByConversationIdAndRole(conversationId, MembershipRole): e.g. how many admins (guards "last admin")
SELECT COUNT(*) AS admin_count FROM memberships
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000002'
  AND role = 'ADMIN';

-- countByUserId(UUID userId): conversations a user belongs to (admin user detail)
SELECT COUNT(*) AS conversation_count FROM memberships
WHERE user_id = '11111111-1111-1111-1111-111111111111';

-- Update per-user preferences (mute / archive a conversation)
--   UPDATE memberships SET muted = TRUE    WHERE user_id = '...' AND conversation_id = '...';
--   UPDATE memberships SET archived = TRUE WHERE user_id = '...' AND conversation_id = '...';

-- deleteByUserId(UUID userId): remove all memberships for a user (account/user deletion)
--   DELETE FROM memberships WHERE user_id = '33333333-3333-3333-3333-333333333333';

-- deleteByConversationId(UUID conversationId): remove all memberships for a conversation
--   DELETE FROM memberships WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000002';


-- ============================================================================
-- 4. MessageRepository
-- ============================================================================

-- findByConversationIdAndSeqGreaterThanOrderBySeqAsc(conversationId, afterSeq, Pageable)
-- Fetch messages after a given seq, ascending. LIMIT emulates the Pageable size.
SELECT * FROM chat_messages
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000001'
  AND seq > 1
ORDER BY seq ASC
LIMIT 50;

-- findFirstByConversationIdOrderBySeqDesc(UUID conversationId): latest message
SELECT * FROM chat_messages
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000001'
ORDER BY seq DESC
LIMIT 1;

-- findByConversationIdOrderBySeqDesc(conversationId, Pageable): newest-first page (history / infinite scroll)
SELECT * FROM chat_messages
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000001'
ORDER BY seq DESC
LIMIT 50 OFFSET 0;

-- findByConversationIdAndDeletedFalseAndBodyContainingIgnoreCaseOrderBySeqDesc(conversationId, q, Pageable)
-- In-conversation message search (skips soft-deleted tombstones)
SELECT * FROM chat_messages
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000001'
  AND deleted = FALSE
  AND LOWER(body) LIKE LOWER('%how%')
ORDER BY seq DESC
LIMIT 50;

-- findMaxSeq(UUID conversationId): highest seq, 0 when none
SELECT COALESCE(MAX(seq), 0) AS max_seq FROM chat_messages
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000001';

-- countByConversationId(UUID conversationId): total messages in a conversation
SELECT COUNT(*) AS message_count FROM chat_messages
WHERE conversation_id = 'aaaaaaaa-0000-0000-0000-000000000001';

-- countByCreatedAtAfter(Instant): messages sent in the last 24 hours (dashboard stats)
SELECT COUNT(*) AS messages_24h FROM chat_messages
WHERE created_at > DATEADD('HOUR', -24, CURRENT_TIMESTAMP);

-- updateStatus(UUID messageId, MessageStatus status)
UPDATE chat_messages
SET status = 'READ'
WHERE id = 'cccccccc-0000-0000-0000-000000000002';

-- Verify the update
SELECT id, status FROM chat_messages
WHERE id = 'cccccccc-0000-0000-0000-000000000002';

-- Edit a message (sets body + edited_at); soft-delete leaves a tombstone
--   UPDATE chat_messages SET body = 'edited text', edited_at = CURRENT_TIMESTAMP WHERE id = 'cccccccc-0000-0000-0000-000000000003';
--   UPDATE chat_messages SET deleted = TRUE, body = NULL WHERE id = 'cccccccc-0000-0000-0000-000000000003';

-- Threaded replies: fetch all replies to a parent message
SELECT * FROM chat_messages
WHERE parent_id = 'cccccccc-0000-0000-0000-000000000001'
ORDER BY seq ASC;


-- ============================================================================
-- 5. MessageReactionRepository
-- ============================================================================

-- findByMessageId(UUID messageId): all reactions on one message
SELECT * FROM message_reactions
WHERE message_id = 'cccccccc-0000-0000-0000-000000000001';

-- findByMessageIdIn(Collection<UUID> messageIds): batch-load reactions for a page of messages
SELECT * FROM message_reactions
WHERE message_id IN (
  'cccccccc-0000-0000-0000-000000000001',
  'cccccccc-0000-0000-0000-000000000002'
);

-- findByMessageIdAndUsernameAndEmoji(messageId, username, emoji): detect an existing toggle
SELECT * FROM message_reactions
WHERE message_id = 'cccccccc-0000-0000-0000-000000000001'
  AND username = 'bob'
  AND emoji = '👍';

-- Aggregate reaction counts per emoji (what the UI renders under a message)
SELECT emoji, COUNT(*) AS count FROM message_reactions
WHERE message_id = 'cccccccc-0000-0000-0000-000000000001'
GROUP BY emoji;

-- deleteByMessageIdAndUsernameAndEmoji(...): remove a reaction (toggle off)
--   DELETE FROM message_reactions WHERE message_id = 'cccccccc-0000-0000-0000-000000000001' AND username = 'bob' AND emoji = '👍';

-- deleteByMessageId(UUID messageId): clear all reactions when a message is removed
--   DELETE FROM message_reactions WHERE message_id = 'cccccccc-0000-0000-0000-000000000001';


-- ============================================================================
-- 6. AuditEventRepository
-- ============================================================================

-- findByActorUsernameContainingIgnoreCase(actor, Pageable): filter the audit log by actor
SELECT * FROM audit_events
WHERE LOWER(actor_username) LIKE LOWER('%alice%')
ORDER BY created_at DESC
LIMIT 50;

-- findByActionContainingIgnoreCase(action, Pageable): filter by action type
SELECT * FROM audit_events
WHERE LOWER(action) LIKE LOWER('%role%')
ORDER BY created_at DESC
LIMIT 50;

-- findByActorUsernameContainingIgnoreCaseAndActionContainingIgnoreCase(actor, action, Pageable)
SELECT * FROM audit_events
WHERE LOWER(actor_username) LIKE LOWER('%alice%')
  AND LOWER(action) LIKE LOWER('%deleted%')
ORDER BY created_at DESC
LIMIT 50;

-- search(actor, action, from, to, Pageable): admin audit query with optional date window
-- (any filter left NULL is ignored)
SELECT * FROM audit_events
WHERE LOWER(actor_username) LIKE LOWER('%alice%')
  AND LOWER(action) LIKE LOWER('%')
  AND created_at >= DATEADD('DAY', -30, CURRENT_TIMESTAMP)
  AND created_at <= CURRENT_TIMESTAMP
ORDER BY created_at DESC
LIMIT 50 OFFSET 0;


